import React from "react";

const SMS = () => {
    return(
        <>
        <div className="container">
            <div className="head-container">
                <h4 className="heading">Send Whatsapp Sms</h4>
                <div>
                    <p>Total Today Campaign:</p>
                    <div>
                        <div><p>Send</p></div>
                    </div>
                </div>

            </div>
        </div>
        </>
    )
}

export default SMS;
